import{c as s,cG as i,cb as a,c8 as t,cf as l,cT as n,ce as e}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"14. M 扩展：乘除法指令","description":"","frontmatter":{"title":"14. M 扩展：乘除法指令","outline":"deep","layout":"doc","prev":{"text":"13. 汇编器、链接器与 ELF","link":"/lang/assembly/13_assembler_linker_elf"},"next":{"text":"15. A 扩展：原子操作指令","link":"/lang/assembly/15_a_extension"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/14_m_extension.md","filePath":"lang/assembly/14_m_extension.md","lastUpdated":1780202472000}'),d={id:"frontmatter-title",tabindex:"-1"};const p=s({name:"lang/assembly/14_m_extension.md"},[["render",function(s,h,p,k,r,c){return i(),a("div",null,[t("h1",d,[l(n(s.$frontmatter.title)+" ",1),h[0]||(h[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=e('<p>第 5 章提到 RISC-V 基础整数指令集 RV64I 不包含乘除法——<code>add</code>/<code>sub</code> 可以解决一切算术的错觉来自补码，但它解决不了&quot;两个 64 位数相乘得 128 位结果&quot;这类需求。M 扩展（Integer Multiplication and Division）填补这个空白，提供硬件整数乘除。本章详述 M 扩展的所有指令、编码、边界行为和编译器优化。</p><h2 id="m-扩展概述" tabindex="-1">M 扩展概述 <a class="header-anchor" href="#m-扩展概述" aria-label="Permalink to “M 扩展概述”">​</a></h2><h3 id="为什么乘除是-扩展-而非-基础" tabindex="-1">为什么乘除是&quot;扩展&quot;而非&quot;基础&quot; <a class="header-anchor" href="#为什么乘除是-扩展-而非-基础" aria-label="Permalink to “为什么乘除是&quot;扩展&quot;而非&quot;基础&quot;”">​</a></h3><p>RISC-V 基础 ISA 刻意将乘除法排除在 RV32I/RV64I 之外，原因有三：</p><ol><li><strong>硬件成本</strong>：32 位乘法器需要约 2000 个逻辑门，除法器更多且慢——在面积敏感的低端 MCU 上这笔开销不值得</li><li><strong>使用频率</strong>：大量嵌入式控制逻辑（传感器读取、GPIO 操作、状态机转移）根本不需要乘除</li><li><strong>软件可替代</strong>：乘法可用循环移位加模拟（Booth 算法精神），除法可用试商减法模拟——慢但可用</li></ol><p>因此，RV64I + M 是常见组合；没有 M 扩展时，编译器调用 <code>__muldi3</code>/<code>__divdi3</code> 等软浮点库函数。</p><h3 id="编码空间" tabindex="-1">编码空间 <a class="header-anchor" href="#编码空间" aria-label="Permalink to “编码空间”">​</a></h3><p>M 扩展指令复用基础整数 R-type 的 opcode 空间：</p><table tabindex="0"><thead><tr><th>属性</th><th>值</th></tr></thead><tbody><tr><td>opcode</td><td><code>0110011</code>（与 add/sub 相同）</td></tr><tr><td>funct7</td><td><code>0000001</code>（bit 30 = 0，区别于 sub/sra 的 funct7=0100000）</td></tr></tbody></table><p>funct3 区分 8 种操作（乘法 4 种 + 除法 4 种），funct7 统一为 <code>0000001</code>。这条设计线索说明：M 扩展的指令&quot;看起来&quot;是 R-type 整数操作的一个子类——解码器只需多检查一层 funct7 的第 0 位是否为 1。</p><h3 id="指令总览" tabindex="-1">指令总览 <a class="header-anchor" href="#指令总览" aria-label="Permalink to “指令总览”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>funct3</th><th>操作描述</th></tr></thead><tbody><tr><td><code>mul</code></td><td>000</td><td>rd = (rs1 * rs2)[63:0]，低 64 位</td></tr><tr><td><code>mulh</code></td><td>001</td><td>有符号乘高 64 位</td></tr><tr><td><code>mulhsu</code></td><td>010</td><td>有符号(rs1) × 无符号(rs2) 高 64 位</td></tr><tr><td><code>mulhu</code></td><td>011</td><td>无符号乘高 64 位</td></tr><tr><td><code>div</code></td><td>100</td><td>有符号除，向零取整</td></tr><tr><td><code>divu</code></td><td>101</td><td>无符号除</td></tr><tr><td><code>rem</code></td><td>110</td><td>有符号余数</td></tr><tr><td><code>remu</code></td><td>111</td><td>无符号余数</td></tr></tbody></table><p>RV64 额外提供 <code>mulw</code>/<code>divw</code>/<code>divuw</code>/<code>remw</code>/<code>remuw</code> 五条 32 位变体（opcode=0111011，funct7=0000001），操作数截取低 32 位，结果符号扩展到 64 位。</p><h2 id="乘法指令" tabindex="-1">乘法指令 <a class="header-anchor" href="#乘法指令" aria-label="Permalink to “乘法指令”">​</a></h2><h3 id="基本形式" tabindex="-1">基本形式 <a class="header-anchor" href="#基本形式" aria-label="Permalink to “基本形式”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 * rs2)[63:0]    低 64 位，有符号与无符号结果相同</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulh   rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 * rs2)[127:64]  有符号 × 有符号的高 64 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulhu  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 * rs2)[127:64]  无符号 × 无符号的高 64 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulhsu rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 * rs2)[127:64]  rs1 有符号，rs2 无符号</span></span></code></pre></div><p>这四条指令覆盖了任意 64 位乘法语义的所有组合。RISC-V 没有单独的 &quot;有符号 128 位结果&quot; 或 &quot;无符号 128 位结果&quot; 指令——而是通过组合 <code>mul</code>（低 64 位）+ <code>mulh</code>/<code>mulhu</code>/<code>mulhsu</code>（高 64 位）来覆盖。低 64 位乘法结果与符号无关（补码的算术性质保证），只需一条 <code>mul</code>。</p><h3 id="_128-位完整乘法" tabindex="-1">128 位完整乘法 <a class="header-anchor" href="#_128-位完整乘法" aria-label="Permalink to “128 位完整乘法”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 计算 a0 * a1，128 位结果存入 t1:t0（t0=低64，t1=高64）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 有符号版本 ----</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t0, a0, a1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 低 64 位（有符号、无符号结果相同）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulh  t1, a0, a1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 高 64 位（有符号）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 无符号版本 ----</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t0, a0, a1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 低 64 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulhu t1, a0, a1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 高 64 位（无符号）</span></span></code></pre></div><p>汇编器建议先写 <code>mulh</code> 再写 <code>mul</code>（先后顺序），因为某些实现可以对相邻的 <code>mulh</code>+<code>mul</code> 对做宏融合——在一条流水线中同时产出高、低 64 位。</p><h3 id="_32-位乘法-rv64m" tabindex="-1">32 位乘法（RV64M） <a class="header-anchor" href="#_32-位乘法-rv64m" aria-label="Permalink to “32 位乘法（RV64M）”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulw rd, rs1, rs2      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = sign_ext((rs1[31:0] * rs2[31:0])[31:0])</span></span></code></pre></div><p><code>mulw</code> 将 rs1 和 rs2 的低 32 位相乘，取结果的低 32 位，符号扩展到 64 位后写入 rd。编译器对 C 语言的 <code>int32_t * int32_t</code> 产生 <code>mulw</code>——语义正确且节省对高 32 位的无关计算。</p><h3 id="常数乘法优化" tabindex="-1">常数乘法优化 <a class="header-anchor" href="#常数乘法优化" aria-label="Permalink to “常数乘法优化”">​</a></h3><p>编译器极少对字面量常数直接生成 <code>mul</code>——移位+加法的组合体效率远高于通用乘法器。以下是常见常数乘法的等价变换：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># t1 = t0 * 3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # t1 = t0 * 2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t1, t0         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = t0 * 2 + t0 = t0 * 3</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># t1 = t0 * 5</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t1 = t0 * 4</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t1, t0         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = t0 * 4 + t0 = t0 * 5</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># t1 = t0 * 10</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t1 = t0 * 8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t2 = t0 * 2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t1, t2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = t0 * 8 + t0 * 2 = t0 * 10</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># t1 = t0 * 12</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t1 = t0 * 8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t2 = t0 * 4</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t1, t2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = t0 * 8 + t0 * 4 = t0 * 12</span></span></code></pre></div><p>RISC-V 没有像 x86 的 <code>lea</code> 那样能在一个周期内完成&quot;移位+加法&quot;的地址生成指令——上述序列需 2-3 条指令，但每条都是单周期 ALU 操作。当乘数是 2 的幂方、或可分解为少量 2 的幂之和时，移位加法优于 <code>mul</code>（无 M 扩展时更是唯一选择）。</p><h3 id="rv32-中的-64-位乘法" tabindex="-1">RV32 中的 64 位乘法 <a class="header-anchor" href="#rv32-中的-64-位乘法" aria-label="Permalink to “RV32 中的 64 位乘法”">​</a></h3><p>RV32M 上计算 64 位乘法的需求催生了 <code>mulh</code>/<code>mulhu</code>/<code>mulhsu</code> 的原始设计动机——只有 32 位寄存器，却需要 64 位结果。以下是 RV32M 上实现 64 位无符号乘法的完整序列：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RV32M: result[63:0] = a[31:0] * b[31:0]</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a_lo: a0, a_hi: a1; b_lo: a2, b_hi: a3</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># result_lo: t0, result_hi: t1</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t0, a0, a2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = a_lo * b_lo (低 32 位)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulhu t1, a0, a2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = a_lo * b_lo (高 32 位)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t2, a1, a2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = a_hi * b_lo</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t1, t1, t2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 += a_hi * b_lo</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t2, a0, a3         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = a_lo * b_hi</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t1, t1, t2         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 += a_lo * b_hi</span></span></code></pre></div><p>这段代码精确反映了小学乘法的竖式展开——四个部分积相加。在 RV64 中同样可用 <code>mulw</code> 系列实现 128 位乘法，原理一致。</p><h2 id="除法指令" tabindex="-1">除法指令 <a class="header-anchor" href="#除法指令" aria-label="Permalink to “除法指令”">​</a></h2><h3 id="基本形式-1" tabindex="-1">基本形式 <a class="header-anchor" href="#基本形式-1" aria-label="Permalink to “基本形式”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 / rs2     有符号除，向零取整</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">divu rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 / rs2     无符号除</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rem  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 % rs2     有符号余数</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">remu rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 % rs2     无符号余数</span></span></code></pre></div><p>RISC-V 的除法遵循 C99 语义：商向零取整，余数满足 <code>dividend = quotient * divisor + remainder</code>，且余数的符号与被除数相同。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例：有符号除法的商与余数</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t0, t1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = 10 / 3 = 3（向零取整，不是 3.33）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rem  t3, t0, t1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = 10 % 3 = 1（10 = 3 * 3 + 1）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t0, t1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = -10 / 3 = -3（向零取整，不是 -4）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rem  t3, t0, t1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = -10 % 3 = -1（-10 = 3 * -3 + (-1)，余数与被除数同号）</span></span></code></pre></div><h3 id="除零行为——risc-v-的特殊选择" tabindex="-1">除零行为——RISC-V 的特殊选择 <a class="header-anchor" href="#除零行为——risc-v-的特殊选择" aria-label="Permalink to “除零行为——RISC-V 的特殊选择”">​</a></h3><p>RISC-V 在除零问题上的设计与其他架构截然不同：<strong>不抛异常，返回特定值</strong>。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 除零的返回值</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">42</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 除法除零</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t0, x0        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = -1（全 1 位模式，即 0xFFFFFFFFFFFFFFFF）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">divu t1, t0, x0        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = 2^64 - 1（MAX_UINT，同样是全 1）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 余数除零</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rem  t1, t0, x0        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = t0（原样返回被除数）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">remu t1, t0, x0        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = t0（原样返回被除数）</span></span></code></pre></div><p>这个设计选择的核心原因：</p><ol><li><strong>无异常开销</strong>：OS 无需处理除零陷阱，控制流不被打断——在嵌入式实时场景中至关重要</li><li><strong>可预测性</strong>：除法永远不会因输入值而导致程序崩溃</li><li><strong>软件检测</strong>：代码可以在除法后立即检查结果是否全 1，自行决定后续策略：</li></ol><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t1, t0, t1          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 执行除法</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">not</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t1              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = ~t1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">beqz t2, handle_divzero  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 如果 t1 全 1（~t1 == 0），说明发生了除零</span></span></code></pre></div><h3 id="溢出-唯一的情况" tabindex="-1">溢出：唯一的情况 <a class="header-anchor" href="#溢出-唯一的情况" aria-label="Permalink to “溢出：唯一的情况”">​</a></h3><p>RISC-V 除法有一个且仅有一个溢出场景：<code>-2^63 / -1</code>。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9223372036854775808</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # -2^63（0x8000000000000000）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t0, t1                 </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 溢出！正确结果 2^63 超出了 64 位有符号范围</span></span></code></pre></div><p>规范规定此场景下 <code>div</code> 返回被除数（即 -2^63），<code>rem</code> 返回 0。实际代码中此场景极罕见，但编写通用库代码时应考虑。</p><h3 id="除以常数优化——强度削减" tabindex="-1">除以常数优化——强度削减 <a class="header-anchor" href="#除以常数优化——强度削减" aria-label="Permalink to “除以常数优化——强度削减”">​</a></h3><p>编译器从不直接对常数做除法——以下面的 <code>x / 10</code> 为例，编译器会生成类似这样的序列：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等效于 t0 = rs1 / 10（无符号）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 核心思路：除以 10 = 乘以 (2^N / 10)，再右移 N 位</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 编译器预先计算 magic number 和 shift amount</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li    t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xCCCCCCCCCCCCCCCD</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 预计算的魔法数（2^67 / 10 的近似）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mulhu t1, t0, t1                </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 高 64 位乘法</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srli  t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # t1 = t1 &gt;&gt; 3</span></span></code></pre></div><p>这个技术称为&quot;除法的强度削减&quot;——将昂贵的除法替换为廉价的乘法+移位。<code>mulhu</code> 将 128 位乘积的高 64 位捕获为&quot;除以 2^64&quot;的近似，再配合右移完成精确除法。有符号除法的强度削减更复杂（需要处理负数向零取整），但原理相同：一次 <code>mulh</code>/<code>mulhu</code> + 若干移位和加法替换一次 <code>div</code>。</p><h3 id="_32-位除法-rv64m" tabindex="-1">32 位除法（RV64M） <a class="header-anchor" href="#_32-位除法-rv64m" aria-label="Permalink to “32 位除法（RV64M）”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">divw  rd, rs1, rs2     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 64 位结果 = sign_ext(32 位 rs1 / 32 位 rs2)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">divuw rd, rs1, rs2     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 无符号版</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">remw  rd, rs1, rs2     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 余数版</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">remuw rd, rs1, rs2     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 无符号余数版</span></span></code></pre></div><p>这些指令对应 C 语言中 <code>int32_t / int32_t</code> 的精确语义。</p><h2 id="性能模型" tabindex="-1">性能模型 <a class="header-anchor" href="#性能模型" aria-label="Permalink to “性能模型”">​</a></h2><h3 id="典型延迟" tabindex="-1">典型延迟 <a class="header-anchor" href="#典型延迟" aria-label="Permalink to “典型延迟”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>典型周期数</th><th>依赖因素</th></tr></thead><tbody><tr><td><code>mul</code></td><td>3-5</td><td>乘法器宽度、流水线级数</td></tr><tr><td><code>mulh</code>/<code>mulhu</code></td><td>3-5</td><td>与 mul 相同（共享乘法器阵列）</td></tr><tr><td><code>div</code>/<code>divu</code></td><td>20-80</td><td>实现算法（SRT / Newton 迭代）、操作数位宽</td></tr><tr><td><code>rem</code>/<code>remu</code></td><td>20-80</td><td>与除法相同（除法器同时产出商和余数）</td></tr></tbody></table><p>RISC-V 规范不保证执行周期数——上述数据基于常见开源核（Rocket、BOOM、C906）的实测。关键是<strong>除法的延迟比乘法大一个数量级</strong>，这是所有 ISA 的共性，来自除法算法的内在串行性。</p><h3 id="m-扩展与编译器最佳实践" tabindex="-1">M 扩展与编译器最佳实践 <a class="header-anchor" href="#m-扩展与编译器最佳实践" aria-label="Permalink to “M 扩展与编译器最佳实践”">​</a></h3><ol><li><strong>循环中的除法是性能杀手</strong>：将 <code>x / d</code> 提到循环外，或改用乘法倒数（如果 d 是常数）</li><li><strong>取模 2 的幂</strong>用 <code>andi</code> 而非 <code>rem</code>：<code>x % 8</code> = <code>andi x, 7</code></li><li><strong>除以 2 的幂</strong>用 <code>srli</code>/<code>srai</code> 而非 <code>div</code>：<code>x / 8</code> = <code>srli x, 3</code></li></ol><p>这些优化的效果不只体现在 M 扩展上——它们让代码在任何情况下都更快，在没有 M 扩展时更是从&quot;不可能&quot;变为&quot;可能&quot;。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>M 扩展复用基础 R-type 的 opcode=<code>0110011</code>，以 funct7=<code>0000001</code> 区分；8 条指令覆盖乘法（funct3=000..011）和除法（funct3=100..111）</li><li>128 位完整乘法用 <code>mul</code>（低 64 位）+ <code>mulh</code>/<code>mulhu</code>（高 64 位）组合；常数乘除编译期优化为移位+加法</li><li>RISC-V 除零不抛异常：<code>div</code> 返 -1、<code>divu</code> 返 MAX、<code>rem</code> 返被除数——这是实时系统友好的设计选择</li><li>除法延迟是乘法的 5-20 倍；取模/除 2 的幂用位运算替代是编写高效汇编的基本素养</li><li>没有 M 扩展时，编译器调用 <code>__muldi3</code>/<code>__divdi3</code> 软浮点库——硬件 M 扩展的存在对性能有量级影响</li></ul>',62))])}]]);export{h as __pageData,p as default};
